  const variantsPayload = document.getElementById("variantsPayload");

  let variantsList = [];

  function renderVariants() {
    variantsBody.innerHTML = "";
    if (variantsList.length === 0) {
      variantsTable.style.display = "none";
      variantsPayload.value = "[]";
      return;
