// Simple image gallery controller
(function () {
  document.addEventListener('DOMContentLoaded', function () {
    const mainImg = document.getElementById('mainProductImage');
    const zoomWrap = document.querySelector('.zoom-wrap');
    if (mainImg) {
      mainImg.addEventListener('click', function () {
        this.classList.toggle('zoomed');
      });
      if (zoomWrap) {
        zoomWrap.addEventListener('mousemove', function (e) {
          if (!mainImg.classList.contains('zoomed')) return;
          const rect = zoomWrap.getBoundingClientRect();
          const x = Math.min(Math.max(e.clientX - rect.left, 0), rect.width);
          const y = Math.min(Math.max(e.clientY - rect.top, 0), rect.height);
          const xp = (x / rect.width) * 100;
          const yp = (y / rect.height) * 100;
          mainImg.style.transformOrigin = xp + '% ' + yp + '%';
        });
        zoomWrap.addEventListener('mouseleave', function () {
          // Optional: reset origin when leaving
          mainImg.style.transformOrigin = '';
        });
      }
    }
    const placeholder = document.getElementById('mainProductImagePlaceholder');
    const thumbs = Array.from(document.querySelectorAll('#thumbStrip .p-thumb'));
    const prevBtn = document.getElementById('prevImageBtn');
    const nextBtn = document.getElementById('nextImageBtn');

    const sources = thumbs.map(t => t.getAttribute('data-src')).filter(Boolean);
    let current = 0;

    function show(index) {
      if (!sources.length) {
        if (prevBtn && nextBtn) { prevBtn.style.display = 'none'; nextBtn.style.display = 'none'; }
        return;
      }
      current = (index + sources.length) % sources.length;
      if (mainImg) {
        mainImg.src = sources[current];
        mainImg.classList.remove('zoomed');
        if (placeholder) placeholder.style.display = 'none';
      }

      thumbs.forEach((t, i) => {
        if (i === current) t.classList.add('border', 'border-primary');
        else t.classList.remove('border', 'border-primary');
      });
    }

    // Initialize
    if (sources.length) {
      // If main image exists and is first in thumbs, current stays 0
      show(0);
    } else {
      if (prevBtn && nextBtn) { prevBtn.style.display = 'none'; nextBtn.style.display = 'none'; }
    }

    // Handlers
    thumbs.forEach((t, i) => {
      t.addEventListener('click', () => show(i));
    });
    if (prevBtn) prevBtn.addEventListener('click', () => show(current - 1));
    if (nextBtn) nextBtn.addEventListener('click', () => show(current + 1));
  });
})();

document.addEventListener("DOMContentLoaded", function () {
  const stars = document.querySelectorAll("#ratingInput i");
  const ratingInput = document.getElementById("ratingValue");

  stars.forEach(star => {
    star.addEventListener("mouseenter", () => {
      const value = star.getAttribute("data-value");
      highlightStars(value);
    });

    star.addEventListener("click", () => {
      const value = star.getAttribute("data-value");
      ratingInput.value = value;
      lockStars(value);
    });

    star.addEventListener("mouseleave", () => {
      lockStars(ratingInput.value);
    });
  });

  function highlightStars(num) {
    stars.forEach(s => {
      s.className = (s.getAttribute("data-value") <= num) ? "fas fa-star" : "far fa-star";
    });
  }

  function lockStars(num) {
    stars.forEach(s => {
      s.className = (s.getAttribute("data-value") <= num) ? "fas fa-star" : "far fa-star";
    });
  }
});

document.addEventListener('DOMContentLoaded', function () {

  // Variants Evaluation Context
  let selectedVariantId = null;
  const priceDisplay = document.getElementById('productPriceDisplay');
  const stockStatus = document.getElementById('productStockStatus');
  const submitBtn = document.getElementById('addToCartSubmitBtn');
  const mobileBtn = document.getElementById('mobileAddToCart');

  const hasVariants = window.__PRODUCT_HAS_VARIANTS__;
  const variantsArray = window.__PRODUCT_VARIANTS__;

  function evaluateVariantSelection() {
    if (!hasVariants) return;

    const sizeRadio = document.querySelector('input[name="variantSize"]:checked');
    const colorRadio = document.querySelector('input[name="variantColor"]:checked');

    const selectedSize = sizeRadio ? sizeRadio.value : undefined;
    const selectedColor = colorRadio ? colorRadio.value : undefined;

    // Find matching variant
    const matched = variantsArray.find(v => {
      const matchSize = v.attributes && v.attributes.Size === selectedSize;
      const matchColor = v.attributes && v.attributes.Color === selectedColor;
      return matchSize && matchColor;
    });

    if (matched) {
      selectedVariantId = matched._id;
      const displayPrice = matched.salesPrice || matched.price;
      priceDisplay.innerHTML = `&#8377;${displayPrice}`;

      if (matched.stock > 0) {
        stockStatus.innerText = `In Stock (${matched.stock} left)`;
        stockStatus.className = 'fw-bold fs-6 text-success my-2';
        if (submitBtn) { submitBtn.disabled = false; submitBtn.innerText = 'Add to Cart'; }
        if (mobileBtn) { mobileBtn.disabled = false; mobileBtn.innerText = 'Add to Cart'; }
      } else {
        stockStatus.innerText = 'Out of Stock';
        stockStatus.className = 'fw-bold fs-6 text-danger my-2';
        if (submitBtn) { submitBtn.disabled = true; submitBtn.innerText = 'Out of Stock'; }
        if (mobileBtn) { mobileBtn.disabled = true; mobileBtn.innerText = 'Out of Stock'; }
      }
    } else {
      selectedVariantId = null;
      if (selectedSize && selectedColor) {
        stockStatus.innerText = 'Configuration Unavailable';
        stockStatus.className = 'fw-bold fs-6 text-warning my-2';
      } else {
        stockStatus.innerText = 'Please select options above';
        stockStatus.className = 'fw-bold fs-6 text-muted my-2';
      }
      if (submitBtn) { submitBtn.disabled = true; submitBtn.innerText = 'Select Options'; }
      if (mobileBtn) { mobileBtn.disabled = true; mobileBtn.innerText = 'Select Options'; }
    }
  }

  // Bind radios
  document.querySelectorAll('.variant-radio').forEach(r => {
    r.addEventListener('change', evaluateVariantSelection);
  });
  // Execute once if pre-selected
  if (hasVariants) evaluateVariantSelection();

  const addToCartForm = document.querySelector('.mx-cart-form');

  if (addToCartForm) {
    addToCartForm.addEventListener('submit', function (e) {
      e.preventDefault();

      if (hasVariants && !selectedVariantId) {
        return Swal.fire('Action Required', 'Please select a valid size and color combination.', 'warning');
      }

      const formData = new FormData(this);
      if (selectedVariantId) {
        formData.append('variantId', selectedVariantId);
      }

      const productId = this.action.split('/').pop();

      const submitButton = this.querySelector('button[type="submit"]');
      const originalText = submitButton.textContent;
      submitButton.disabled = true;
      submitButton.textContent = 'Adding...';

      fetch(`/cart/add/${productId}`, {
        method: 'POST',
        headers: {
          'Accept': 'application/json',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams(formData)
      })
        .then(async (response) => {
          const data = await response.json();

          if (response.status === 401) {
            Swal.fire({
              icon: 'warning',
              title: 'Login Required',
              text: 'You must be logged in to add items to your cart.',
              confirmButtonText: 'Login',
              showCancelButton: true,
              cancelButtonText: 'Cancel',
              confirmButtonColor: '#fca120'
            }).then(result => {
              if (result.isConfirmed) {
                window.location.href = '/login';
              }
            });
            throw new Error('User not authenticated');
          }

          return data;
        })

        .then(data => {
          if (!data) return;

          if (!data.success) {
            Swal.fire({
              icon: 'error',
              title: 'Cannot add to cart',
              text: data.message || 'This product is currently unavailable',
              confirmButtonColor: '#d33'
            });
            return;
          }

          if (window.updateNavbarCounts && typeof data.cartCount !== 'undefined') {
            window.updateNavbarCounts({ cartCount: data.cartCount });
          }

          Swal.fire({
            toast: true,
            position: 'top-end',
            icon: 'success',
            title: data.message || 'Added to cart',
            showConfirmButton: false,
            timer: 1500,
            timerProgressBar: true
          });
        })

        .catch(error => {
          console.error('Error:', error);
        })
        .finally(() => {
          submitButton.disabled = false;
          submitButton.textContent = originalText;
        });
    });
  }
});

